// Package llm is aipet's ONLY model-calling code path: the opt-in "api"
// voice mode (HOST_INTEGRATION.md §10), where the pet's one daily spoken
// line is generated by the cheapest Claude model using the user's own
// credentials instead of picked from the embedded phrasebook.
//
// The token-budget contract this package enforces:
//
//   - opt-in only: nothing here runs unless `aipet config voice api`
//   - one generation per (day, mood, personality) — cached on disk, so a
//     normal day costs ONE call of ~150 input + ≤60 output tokens
//     (≈ $0.0004 at Haiku pricing; cents per month, not dollars)
//   - a hard daily call cap as a backstop against mood thrash
//   - hard timeout, and every failure (no credentials, offline, refusal,
//     cap hit) degrades silently to the embedded canned line — the pet
//     never breaks and never blocks a host surface
//
// Credentials are never stored or logged by aipet: the SDK's zero-arg
// client resolves the user's existing ANTHROPIC_API_KEY / auth token /
// `ant auth login` profile at call time. The only network egress is
// api.anthropic.com (or the SDK's configured base URL).
package llm

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/anthropics/anthropic-sdk-go"
	"github.com/anthropics/anthropic-sdk-go/option"
)

// DefaultModel is the cheapest current Claude model — the right tier for a
// 15-word one-liner. Overridable via `aipet config voice_model` for users
// who want a different one; the budget contract (max_tokens, caching, cap)
// applies regardless of model.
const DefaultModel = "claude-haiku-4-5"

// maxOutputTokens caps the generation hard: a voice line is ~15 words. Even
// a runaway response cannot cost more than this.
const maxOutputTokens = 60

// requestTimeout keeps /aipet snappy: if the API hasn't answered in this
// window, the canned line ships instead. Generation is a garnish, never a
// blocker.
const requestTimeout = 3 * time.Second

// maxCallsPerDay is the backstop cap on generations, whatever happens with
// mood changes or cache resets. At ~$0.0004/call this bounds worst-case
// spend at well under a cent per day.
const maxCallsPerDay = 8

// personaStyle is the one-line style directive per personality, kept tiny
// because every token here is paid input on the user's account.
var personaStyle = map[string]string{
	"playful":    "playful, warm, a little odd",
	"funny":      "funny, absurd, self-aware humor",
	"nonchalant": "dry, unbothered, lowercase energy",
	"snarky":     "lightly sarcastic, teasing but affectionate",
	"coach":      "brisk, encouraging, action-oriented",
}

// GenerateLine makes the single, tightly-budgeted API call. It is package-
// private plumbing — external callers go through Line (cache + cap +
// fallback). extraOpts exists so tests can point the client at a mock
// server; production passes none and the SDK resolves the user's real
// credentials.
func generateLine(ctx context.Context, model, personality string, isEgg bool, mood, statusHint string, extraOpts ...option.RequestOption) (string, error) {
	client := anthropic.NewClient(extraOpts...)

	style, ok := personaStyle[personality]
	if !ok {
		style = personaStyle["playful"]
	}
	state := "mood: " + mood
	if isEgg {
		state = "still an unhatched egg"
	}
	if statusHint != "" {
		state += " · " + statusHint
	}

	ctx, cancel := context.WithTimeout(ctx, requestTimeout)
	defer cancel()

	resp, err := client.Messages.New(ctx, anthropic.MessageNewParams{
		Model:     anthropic.Model(model),
		MaxTokens: maxOutputTokens,
		System: []anthropic.TextBlockParam{{
			Text: "You are a tiny terminal pet (a Codeling) that grows from its keeper's coding activity. Reply with exactly ONE line, max 15 words, in this voice: " + style + ". First person, no emoji, no quotes, never sycophantic, never guilt-tripping.",
		}},
		Messages: []anthropic.MessageParam{
			anthropic.NewUserMessage(anthropic.NewTextBlock("Say one line to your keeper. Your state: " + state)),
		},
	})
	if err != nil {
		return "", err
	}
	if resp.StopReason == anthropic.StopReasonRefusal {
		return "", fmt.Errorf("model refused")
	}
	for _, block := range resp.Content {
		if t, ok := block.AsAny().(anthropic.TextBlock); ok {
			return sanitizeLine(t.Text), nil
		}
	}
	return "", fmt.Errorf("no text in response")
}

// sanitizeLine hardens generated text for terminal display, the same
// posture the collector takes with session-log content: strip control
// characters and newlines, collapse whitespace, cap length. Model output
// is friendly but it is still remote content headed for a terminal.
func sanitizeLine(s string) string {
	var b strings.Builder
	for _, r := range s {
		if r == '\n' || r == '\t' {
			b.WriteRune(' ')
			continue
		}
		if r < 0x20 || r == 0x7f {
			continue
		}
		b.WriteRune(r)
	}
	out := strings.Join(strings.Fields(b.String()), " ")
	out = strings.Trim(out, `"'`)
	if len(out) > 140 {
		out = out[:140]
	}
	return out
}
